import { IMessageComposer } from '@nitrots/nitro-renderer';

export class CallPoliceComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(username: string, figure: string, message: string) {
        const avatarHead = `https://www.habbo.com/habbo-imaging/avatarimage?figure=${figure}&headonly=1&direction=2`;
        this._data = [username, avatarHead, message];
        console.log('[📤] CallPoliceComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
